import Navbar from "../../components/Navbar/Navbar";
import SummaryCard from '../../components/SummaryCard/SummaryCard'
import "./Dashboard.css";

function Dashboard() {
  return (
    <>
    <div className="dashboard">
      <Navbar />
      <p className="main-heading">Summary</p>
      <div className="summary-container">
        <SummaryCard title="Income" amount="100000" className="income"/>
        <SummaryCard title="Expenses" amount="40000" className="expenses"/>
        <SummaryCard title="Balance" amount="60000" className="balance"/>
      </div>
    </div>
    </>
  );
}

export default Dashboard;
